#!/usr/bin/env python3
import sys
from atcoder import dsu
from bisect import bisect_left
from collections import defaultdict, Counter
from collections import deque
# import pypyjit
# pypyjit.set_param(inlining=0)     # or pypyjit.set_param('max_unroll_recursion=-1')

sys.setrecursionlimit(10 ** 6)

INF = 2 ** 64 - 1


# Generated by 2.16.0 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
def main():
    N, Q = map(int, input().split())
    A = list(map(int, input().split()))

    a_cnt = Counter(A)
    a_sort = sorted(a_cnt.items(), key=lambda x: x[0])

    def solve():
        K = int(input())
        B = list(map(lambda x: int(x) - 1, input().split()))

        b_cnt = defaultdict(int)
        for b in B:
            b_cnt[A[b]] += 1
        
        for a, num in a_sort:
            if b_cnt[a] < num:
                print(a)
                break

    for _ in range(Q):
        solve()

if __name__ == '__main__':
    main()
